import { useEffect, useState } from "react";
import { Footer } from "./Footer";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import pattern from "../slike/pattern4.jpg";

export function PocetnaRecepcionar() {
  const [sobe, setSobe] = useState([]);
  const [izabranaSoba, setIzabranaSoba] = useState(null);
  const [showModal, setShowModal] = useState(false);

  // Ucitavanje soba iz backenda
  useEffect(() => {
    fetch("http://localhost:8080/rooms/all")
      .then((res) => res.json())
      .then((data) => {
        // API vraca objekat sa "values" unutar "data"
        if (data && data.data && data.data.values) {
          setSobe(data.data.values);
        }
      })
      .catch((err) => console.error("Greška pri učitavanju soba:", err));
  }, []);

  // Brisanje sobe
  const handleDelete = async (idSoba) => {
    if (window.confirm("Da li ste sigurni da želite da obrišete ovu sobu?")) {
      await fetch("http://localhost:8080/rooms/delete", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(idSoba),
      });
      setSobe(sobe.filter((s) => s.idSoba !== idSoba));
    }
  };

  // Otvaranje modala za izmenu
  const handleEdit = (soba) => {
    setIzabranaSoba({ ...soba });
    setShowModal(true);
  };

  // Čuvanje izmenjenih podataka
  const handleSave = async () => {
    await fetch("http://localhost:8080/rooms/update", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(izabranaSoba),
    });
    setShowModal(false);
    const updated = sobe.map((s) =>
      s.idSoba === izabranaSoba.idSoba ? izabranaSoba : s
    );
    setSobe(updated);
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
      }}
    >
      <NavBarRecepcionar />

      <div
        style={{
          backgroundImage: `url(${pattern})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          minHeight: "100vh",
          padding: "40px",
        }}
      >
  <h2
      style={{
        color: "white",
        marginBottom: "30px",
      }}
    >
      Lista soba
    </h2>

        <div
          style={{
            display: "flex",
            flexWrap: "wrap",
            justifyContent: "center",
            gap: "20px",
            marginTop: "30px",
          }}
        >
          {sobe.map((soba) => (
            <div
              key={soba.idSoba}
              style={{
                backgroundColor: "rgba(255, 255, 120, 1)",
                width: "250px",
                borderRadius: "15px",
                padding: "15px",
                boxShadow: "0 2px 10px rgba(0,0,0,0.2)",
                textAlign: "center",
              }}
            >


              {/* prikaz slike */}
              {soba.slika && (
                <img
                  src={`http://localhost:8080/uploads/${soba.slika.split("/").pop()}`}
                  alt="Slika sobe"
                  style={{
                    width: "100%",
                    height: "150px",
                    borderRadius: "10px",
                    objectFit: "cover",
                  }}
                />

              )}

              <h3>{soba.naziv}</h3>
              <p>Tip sobe: {soba.tipSobe ? soba.tipSobe.naziv : "Nepoznat"}</p>
              <p>
                Cena po noći:{" "}
                {soba.tipSobe
                  ? soba.tipSobe.cenaPoNoci + " RSD"
                  : Math.floor(Math.random() * 5000 + 3000) + " RSD"}
              </p>


              <div style={{ marginTop: "10px" }}>
                <button
                  onClick={() => handleEdit(soba)}
                  style={{
                    marginRight: "10px",
                    backgroundColor: "#eee380ff",
                    color: "white",
                    border: "none",
                    borderRadius: "5px",
                    padding: "5px 10px",
                    cursor: "pointer",
                  }}
                >
                  ✏️ Izmeni
                </button>
                <button
                  onClick={() => handleDelete(soba.idSoba)}
                  style={{
                    backgroundColor: "#eee380ff",
                    color: "white",
                    border: "none",
                    borderRadius: "5px",
                    padding: "5px 10px",
                    cursor: "pointer",
                  }}
                >
                  🗑️ Obriši
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* MODAL ZA IZMENE */}
      {showModal && (
        <div
          style={{
            position: "fixed",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%",
            backgroundColor: "rgba(0,0,0,0.6)",
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
          }}
        >
          <div
            style={{
              backgroundColor: "white",
              padding: "20px",
              borderRadius: "10px",
              width: "400px",
            }}
          >
            <h3>Izmeni sobu</h3>
            <label>Naziv:</label>
            <input
              type="text"
              value={izabranaSoba.naziv}
              onChange={(e) =>
                setIzabranaSoba({ ...izabranaSoba, naziv: e.target.value })
              }
              style={{ width: "100%", marginBottom: "10px" }}
            />
            <label>Kapacitet:</label>
            <input
              type="number"
              value={izabranaSoba.kapacitet}
              onChange={(e) =>
                setIzabranaSoba({
                  ...izabranaSoba,
                  kapacitet: e.target.value,
                })
              }
              style={{ width: "100%", marginBottom: "10px" }}
            />
            <label>Cena:</label>
            <input
              type="number"
              value={izabranaSoba.cena}
              onChange={(e) =>
                setIzabranaSoba({ ...izabranaSoba, cena: e.target.value })
              }
              style={{ width: "100%", marginBottom: "10px" }}
            />
            <div style={{ display: "flex", justifyContent: "flex-end" }}>
              <button
                onClick={() => setShowModal(false)}
                style={{
                  marginRight: "10px",
                  backgroundColor: "gray",
                  color: "white",
                  border: "none",
                  borderRadius: "5px",
                  padding: "5px 10px",
                }}
              >
                Otkaži
              </button>
              <button
                onClick={handleSave}
                style={{
                  backgroundColor: "green",
                  color: "white",
                  border: "none",
                  borderRadius: "5px",
                  padding: "5px 10px",
                }}
              >
                Sačuvaj
              </button>
            </div>
          </div>
        </div>
      )}

      <Footer />
    </div>
  );
}
